namespace sv_51a005155ba54494a6c2260807287f6f.Components;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

@implements IAsyncDisposable
@inject IJSRuntime JS

<CascadingValue Value="currentSize" Name="ScreenSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize currentSize = ScreenSize.Desktop;

    private IJSObjectReference? module;
    private DotNetObjectReference<ScreenSizeProvider>? objRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            objRef = DotNetObjectReference.Create(this);
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./Components/ScreenSizeProvider.razor.js");
            var width = await module.InvokeAsync<int>("addResizeListener", objRef);
            UpdateSize(width);
        }
    }

    [JSInvokable]
    public void OnBrowserResize(int width)
    {
        var newSize = Categorize(width);
        if (newSize != currentSize)
        {
            currentSize = newSize;
            StateHasChanged();
        }
    }

    private void UpdateSize(int width)
    {
        var newSize = Categorize(width);
        if (newSize != currentSize)
        {
            currentSize = newSize;
            StateHasChanged();
        }
    }

    private static ScreenSize Categorize(int width) => width switch
    {
        < 768 => ScreenSize.Mobile,
        < 1024 => ScreenSize.Tablet,
        _ => ScreenSize.Desktop
    };

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            try
            {
                await module.InvokeVoidAsync("removeResizeListener");
                await module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit already gone — safe to ignore
            }
        }
        objRef?.Dispose();
    }
}

let dotNetRef = null;
let handler = null;

export function addResizeListener(objRef) {
    dotNetRef = objRef;
    handler = () => {
        dotNetRef.invokeMethodAsync('OnBrowserResize', window.innerWidth);
    };
    window.addEventListener('resize', handler);
    return window.innerWidth;
}

export function removeResizeListener() {
    if (handler) {
        window.removeEventListener('resize', handler);
        handler = null;
    }
    dotNetRef = null;
}

